// Normalise and slightly structure the CV text from "Extract from File"

// 1) Raw text from the file extraction node
let text = $json.text || "";

// 2) Normalise whitespace to reduce noise for the model
text = text.replace(/\r/g, "\n");
text = text.replace(/\u00A0/g, " "); // non-breaking spaces
text = text.replace(/\t/g, " ");
text = text.replace(/\n{3,}/g, "\n\n").trim();

// 3) Capture a short header snippet (good for name detection)
// Take the first 15 non-empty lines as cv_header
const lines = text.split("\n").map(l => l.trim()).filter(l => l !== "");
const headerLines = lines.slice(0, 15);
const cv_header = headerLines.join("\n");

// 4) Optionally limit total length to protect token budget
const maxChars = 25000;
if (text.length > maxChars) {
  text = text.slice(0, maxChars);
}

return [
  {
    json: {
      cv_text: text,
      cv_header,
    },
  },
];

