// Helper to parse the AI Agent output for each item
function parseAgentOutput(itemJson) {
  // Most common case: { output: "{...json...}" }
  if (itemJson && typeof itemJson.output === 'string') {
    return JSON.parse(itemJson.output);
  }
  // If the whole json is the string
  if (typeof itemJson === 'string') {
    return JSON.parse(itemJson);
  }
  // If the Agent ever starts returning an object directly
  if (itemJson && typeof itemJson === 'object') {
    return itemJson;
  }
  return null;
}

const items = $input.all();

return items.map(item => {
  let cls;
  try {
    cls = parseAgentOutput(item.json);
  } catch (e) {
    return {
      json: {
        error: 'Could not parse AI Agent output as JSON: ' + e.message,
        raw: item.json,
      },
    };
  }

  if (!cls || cls.tier_id == null) {
    return {
      json: {
        error: 'AI Agent output does not contain tier_id',
        parsed: cls,
        raw: item.json,
      },
    };
  }

  // Find the tier from the rate grid by id
  let tier = rateGrid.find(t => t.id === Number(cls.tier_id));

  // If tier_id and tier_scio_level disagree, trust the name
  if ((!tier || !tier.id) && cls.tier_scio_level) {
    const byName = rateGrid.find(t => t.scio_level === cls.tier_scio_level);
    if (byName) {
      tier = byName;
      cls.tier_id = byName.id;
    }
  }

  if (!tier) {
    return {
      json: {
        error: 'No rate grid entry found for tier_id ' + cls.tier_id,
        classification: cls,
      },
    };
  }

  // Clamp seniority_score to [0,1]
  let s = Number(cls.seniority_score);
  if (!Number.isFinite(s)) s = 0.5;
  if (s < 0) s = 0;
  if (s > 1) s = 1;

  const min = tier.br_min_eur;
  const max = tier.br_max_eur;
  const avg = Math.round(((min + max) / 2) * 10) / 10;
  const recommended = Math.round((min + s * (max - min)) * 10) / 10;

  return {
    json: {
      ...cls,
      min_buying_rate_eur: min,
      max_buying_rate_eur: max,
      avg_buying_rate_eur: avg,
      recommended_buying_rate_eur: recommended,
    },
  };
});

// Extract basic file metadata from "Download file"
